class Solution:
    def buildTree(self, preorder: list[int], inorder: list[int]):
        idx = {v: i for i, v in enumerate(inorder)}   # 值 -> 在中序里的下标,O(1) 查根位置

        def build(pl, pr, il, ir):   # 用前序[pl..pr] 与 中序[il..ir] 建子树
            if pl > pr:
                return None
            root_val = preorder[pl]  # 前序第一个就是根
            i = idx[root_val]        # 根在中序里的位置
            left_len = i - il        # 左子树结点个数
            return TreeNode(
                root_val,
                build(pl + 1, pl + left_len, il, i - 1),       # 左子树
                build(pl + left_len + 1, pr, i + 1, ir),       # 右子树
            )

        return build(0, len(preorder) - 1, 0, len(inorder) - 1)
